SELECT COLLECT_LOG_ID, SERVER_ID, SERVER_IP, SOURCE_FILE_PATH, LOG_TYPE, LOG_ID, LOG_TIMESTAMP, LOG_CONTENT, LOG_VALUE, RAW_LOG, COLLECT_DATE, COLLECT_DATETIME, SCHEDULE_TYPE, LINE_NUMBER, CREATED_AT FROM TB_COLLECT_LOG
COLLECT_DATE = #{collectDate} AND SERVER_ID = #{serverId} AND LOG_TYPE = #{logType}
AND LOG_ID = #{logId}
ORDER BY LOG_TIMESTAMP ASC
